+}
+
+impl ChatConnector {
+    #[must_use]
+    pub fn new() -> Self {
+        Self {
+            base: Arc::new(BaseConnector::new(ConnectorId::from_static("google-chat"))),
+            client: None,
+            verifier: None,
+            session_id: None,
+        }
