+        } else {
+            "not_configured"
+        };
+        let metrics = self.base.metrics();
+        Ok(json!({
+            "status": status,
+            "metrics": {
+                "requests_total": metrics.requests_total,
+                "requests_error": metrics.requests_error,
+            }
+        }))
+    }
