+/// Google People API client with retry logic and shared Google execution.
+pub struct GooglePeopleClient {
+    executor: GoogleRestExecutor,
+    auth: GoogleMaterializedAuth,
+    base_url: String,
+    max_retries: u32,
+    initial_delay_ms: u64,
+    max_delay_ms: u64,
+    total_requests: AtomicU64,
+}
