+        Ok(Self {
+            executor: GoogleRestExecutor::new().with_client(http),
+            auth,
+            base_url: DEFAULT_BASE_URL.to_string(),
+            max_retries: 3,
+            initial_delay_ms: 1000,
+            max_delay_ms: 60_000,
+            total_requests: AtomicU64::new(0),
