+            .iter()
+            .any(|check| check.status == DoctorStatus::Unhealthy)
+        {
+            DoctorStatus::Unhealthy
+        } else if checks
+            .iter()
+            .any(|check| check.status == DoctorStatus::Degraded)
+        {
+            DoctorStatus::Degraded
+        } else {
+            DoctorStatus::Healthy
+        };
